import React, { useEffect, useRef } from 'react';
import { Container, Row, Button } from 'reactstrap';
import { NavLink, Link } from 'react-router-dom';

import logo from "../../assets/images/logo.png";
import "./header.css";

const nav__links = [
  {
    path: '/home',
    display: 'Home'
  },
  {
    path: '/about',
    display: 'About'
  },
  {
    path: '/tours',
    display: 'Tours'
  },
  {
    path: '/contact',
    display: 'Contact'
  },
];

const Header = () => {

  const headerRef = useRef(null);

  const stickyHeaderFunc = () => {
    window.addEventListener('scroll', () => {
      if (document.body.scrollTop > 80 || document.documentElement.scrollTop > 80) {
        headerRef.current.classList.add('sticky__header');
      } else {
        headerRef.current.classList.remove('sticky__header');
      }
    });
  };

  useEffect(() => {
    stickyHeaderFunc();
    return () => window.removeEventListener('scroll', stickyHeaderFunc);
  });

  return (
    <header className='header' ref={headerRef}>
      <Container>
        <Row>
          <div className='nav__wrapper d-flex aligh-items-center justify-content-between'>

            {/*===============Logo=================*/}
            <div className='logo'>
              <img src={logo} alt='' />
            </div>
            {/*============Logo end================*/}

            {/*============Menu start==============*/}
            <div className='naviagtion'>
              <ul className='menu d-flex align-items-center gap-5'>
                {nav__links.map((item, index) => (
                  <li className='nav__item' key={index}>
                    <NavLink
                      to={item.path}
                      className={({ isActive }) => isActive ? "active__link" : ""}
                    >
                      {item.display}
                    </NavLink>
                  </li>
                ))}
              </ul>
            </div>
            {/*=============Menu end===============*/}

            <div className='nav__right d-flex align-items-center gap-4'>
              <ul className='menu d-flex align-items-center gap-3'>
                <li className='nav__item nav__btn-item'>
                  <NavLink
                    to='/login'
                    className={({ isActive }) => isActive ? "active__link" : ""}
                  >
                    Login
                  </NavLink>
                </li>
                <li>
                  <Button className='btn primary__btn'>
                    <Link to='/register'>Register</Link>
                  </Button>
                </li>
              </ul>

              <span className='mobile__menu'>
                <i className="ri-menu-line"></i>
              </span>
            </div>
          </div>
        </Row>
      </Container>
    </header>
  );
};

export default Header;
